<?php
/**
 * JGW Dietetics — Theme Functions
 */

if ( ! defined( 'ABSPATH' ) ) exit;

// ── Theme Setup ───────────────────────────────────────────────────────────────
function jgw_setup() {
    add_theme_support( 'title-tag' );
    add_theme_support( 'post-thumbnails' );
    add_theme_support( 'html5', [ 'search-form', 'comment-form', 'gallery', 'caption' ] );
    add_theme_support( 'custom-logo' );

    register_nav_menus( [
        'primary' => __( 'Primary Navigation', 'jgw' ),
        'footer'  => __( 'Footer Navigation', 'jgw' ),
    ] );
}
add_action( 'after_setup_theme', 'jgw_setup' );

// ── Enqueue Styles & Scripts ──────────────────────────────────────────────────
function jgw_enqueue_assets() {
    $ver = wp_get_theme()->get( 'Version' );

    // Main stylesheet
    wp_enqueue_style( 'jgw-main', get_template_directory_uri() . '/assets/css/main.css', [], $ver );

    // Theme JS
    wp_enqueue_script( 'jgw-main', get_template_directory_uri() . '/assets/js/main.js', [], $ver, true );
}
add_action( 'wp_enqueue_scripts', 'jgw_enqueue_assets' );

// ── Excerpt length ────────────────────────────────────────────────────────────
function jgw_excerpt_length() { return 25; }
add_filter( 'excerpt_length', 'jgw_excerpt_length' );

function jgw_excerpt_more() { return '…'; }
add_filter( 'excerpt_more', 'jgw_excerpt_more' );

