// ── Helper: stars ─────────────────────────────────────────────────────────────
function jgw_stars( $count = 5 ) {
    $out = '<div class="testimonial-stars">';
    for ( $i = 0; $i < $count; $i++ ) {
        $out .= jgw_icon( 'star' );
    }
    $out .= '</div>';
    return $out;
}
